  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_I' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'listening', 29, '여자 :아이 통장을 하나 만들려고 하는데요.
